import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { api, getAuthToken, isSignupComplete } from "../api";

export default function Home() {
  const navigate = useNavigate();
  const [stats, setStats] = useState({ shops: 0, medicines: 0 });
  const isLoggedIn = Boolean(getAuthToken());

  useEffect(() => {
    const loadStats = async () => {
      try {
        const [shopsRes, medicinesRes] = await Promise.all([
          api.get("/shops/"),
          api.get("/medicines/"),
        ]);
        const medicineCount = Array.isArray(medicinesRes.data)
          ? medicinesRes.data.length
          : (medicinesRes.data.count || 0);
        setStats({ shops: shopsRes.data.length, medicines: medicineCount });
      } catch (err) {
        // Keep default stats if backend is unavailable.
      }
    };

    loadStats();
  }, []);

  return (
    <div className="page">
      <div className="page-header">
        <h1>💊 Welcome to MedCompare</h1>
        <p>Find and compare quality medicines from nearby shops</p>
      </div>

      {!isLoggedIn && (
        <div className="hero-card">
          <h2>Join Our Medicine Platform</h2>
          <p>Get access to thousands of quality medicines at competitive prices</p>
          <div className="hero-buttons">
            <button onClick={() => navigate(isSignupComplete() ? "/login" : "/signup")} className="btn-hero">Sign In</button>
            <button onClick={() => navigate("/signup")} className="btn-hero btn-primary">Create Account</button>
          </div>
        </div>
      )}

      <div className="stats-grid">
        <div className="stat-card">
          <div className="stat-icon">🏪</div>
          <div className="stat-content">
            <div className="stat-number">{stats.shops}</div>
            <div className="stat-label">Partner Shops</div>
          </div>
        </div>
        
        <div className="stat-card">
          <div className="stat-icon">💊</div>
          <div className="stat-content">
            <div className="stat-number">{stats.medicines}</div>
            <div className="stat-label">Medicines Available</div>
          </div>
        </div>
        
        <div className="stat-card">
          <div className="stat-icon">✓</div>
          <div className="stat-content">
            <div className="stat-number">100%</div>
            <div className="stat-label">Verified Quality</div>
          </div>
        </div>
      </div>

      {isLoggedIn && (
        <div className="quick-actions">
          <h2>Quick Actions</h2>
          <div className="actions-grid">
            <button onClick={() => navigate("/search")} className="action-btn">
              <div className="action-icon">🔍</div>
              <div className="action-label">Search Medicines</div>
            </button>
            <button onClick={() => navigate("/cart")} className="action-btn">
              <div className="action-icon">🛒</div>
              <div className="action-label">View Cart</div>
            </button>
            <button onClick={() => navigate("/orders")} className="action-btn">
              <div className="action-icon">📦</div>
              <div className="action-label">Order History</div>
            </button>
            <button onClick={() => navigate("/shop-register")} className="action-btn">
              <div className="action-icon">🏪</div>
              <div className="action-label">Manage Store</div>
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
